const toKey = (x: number, y: number): string => `${x},${y}`;

export const nextGeneration = (cells: [number, number][]): [number, number][] => {
  const alive = new Set(cells.map(([x, y]) => toKey(x, y)));

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(toKey(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const survivors = cells.filter(([x, y]) => {
    const neighbors = countNeighbors(x, y);
    return neighbors === 2 || neighbors === 3;
  });

  const candidates = new Set<string>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = toKey(x + dx, y + dy);
        if (!alive.has(key)) {
          candidates.add(key);
        }
      }
    }
  }

  const births: [number, number][] = [];
  for (const key of candidates) {
    const [x, y] = key.split(",").map(Number);
    if (countNeighbors(x, y) === 3) {
      births.push([x, y]);
    }
  }

  return [...survivors, ...births];
};

